--
-- Structure de la table `demandemissions`
--

DROP TABLE IF EXISTS `demandemissions`;
CREATE TABLE IF NOT EXISTS `demandemissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `reference` varchar(50) DEFAULT NULL,
  `id_demandeurs` int NOT NULL,
  `motif` varchar(255) NOT NULL,
  `destination` varchar(100) NOT NULL,
  `dateDepart` date NOT NULL,
  `dateRetour` date NOT NULL,
  `portee` enum('National','Continental','International') NOT NULL,
  `id_workflow` int DEFAULT NULL,
  `statut` enum('Brouillon','En attente','Validée','Rejetée','En cours','Effectuée') DEFAULT 'Brouillon',
  `est_ordre_mission` tinyint DEFAULT '0' COMMENT '0=Demande, 1=Ordre de mission',
  `id_chauffeur` int DEFAULT NULL,
  `id_vehicule` int DEFAULT NULL,
  `categorie_socio_pro_principale` varchar(100) DEFAULT NULL,
  `etape_creation` varchar(50) DEFAULT 'DEMANDE' COMMENT 'DEMANDE | CATEGORIE | ORDRE_CREE | RESSOURCE | VALIDATION | FINALISE',
  `id_ordre_lié` int DEFAULT NULL,
  `date_soumission` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `numero_ordre` (`reference`),
  UNIQUE KEY `reference` (`reference`),
  KEY `id_demandeur` (`id_demandeurs`),
  KEY `fk_demande_chauffeur` (`id_chauffeur`),
  KEY `fk_demande_vehicule` (`id_vehicule`)
) ENGINE=InnoDB AUTO_INCREMENT=36 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

