--
-- Structure de la table `missionnaires`
--

DROP TABLE IF EXISTS `missionnaires`;
CREATE TABLE IF NOT EXISTS `missionnaires` (
  `id_missionnaire` int NOT NULL AUTO_INCREMENT,
  `id_mission` int NOT NULL,
  `nom` varchar(100) NOT NULL,
  `prenom` varchar(100) NOT NULL,
  `fonction` varchar(100) DEFAULT NULL,
  `email` varchar(200) DEFAULT NULL,
  `est_chef_mission` tinyint(1) DEFAULT '0',
  `categorie_socio_pro` enum('Cadre Dirigeant','Cadres supérieurs','Cadres','Haute maîtrise','Moyenne maîtrise','Ouvriers & Empl. (H.Q.)','Ouvriers & Empl. (Qual.)','Ouvriers & Empl. (Base)','Ouvriers & Empl. (tous)') DEFAULT NULL,
  `frais_hebergement` decimal(10,2) DEFAULT '0.00',
  `frais_restauration` decimal(10,2) DEFAULT '0.00',
  `date_creation` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id_missionnaire`),
  KEY `id_demande` (`id_mission`)
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

