--
-- Structure de la table `missions_preplanifiees`
--

DROP TABLE IF EXISTS `missions_preplanifiees`;
CREATE TABLE IF NOT EXISTS `missions_preplanifiees` (
  `id_preplan` int NOT NULL AUTO_INCREMENT,
  `id_demandemission` int NOT NULL,
  `delai_soumission_avant_depart` int DEFAULT '5' COMMENT 'Jours avant date de départ pour soumission automatique',
  `statut_preplan` enum('Programmée','Soumise','Validée','Rejetée','Annulée') DEFAULT 'Programmée',
  `date_creation` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `date_modification` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id_preplan`),
  UNIQUE KEY `unique_demandemission` (`id_demandemission`),
  KEY `id_demandemission` (`id_demandemission`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

