--
-- Structure de la table `notations_chauffeur`
--

DROP TABLE IF EXISTS `notations_chauffeur`;
CREATE TABLE IF NOT EXISTS `notations_chauffeur` (
  `id_notation` int NOT NULL AUTO_INCREMENT,
  `id_demande` int NOT NULL,
  `id_chauffeur` int NOT NULL,
  `id_missionnaire_notant` int NOT NULL,
  `note` int DEFAULT NULL,
  `commentaire` text,
  `date_notation` timestamp NULL DEFAULT NULL,
  `lien_token` varchar(191) DEFAULT NULL,
  `token_utilise` tinyint(1) DEFAULT '0',
  `date_creation` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id_notation`),
  UNIQUE KEY `lien_token` (`lien_token`),
  KEY `id_chauffeur` (`id_chauffeur`),
  KEY `id_missionnaire_notant` (`id_missionnaire_notant`),
  KEY `fk_notation_demande` (`id_demande`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

