--
-- Structure de la table `ordres_missions`
--

DROP TABLE IF EXISTS `ordres_missions`;
CREATE TABLE IF NOT EXISTS `ordres_missions` (
  `id_ordre` int NOT NULL AUTO_INCREMENT,
  `id_demande` int NOT NULL,
  `moyen_transport_libelle` varchar(100) DEFAULT 'Transport routier',
  `statut_ordre` enum('En attente','En cours','Effectué','Annulé') DEFAULT 'En attente',
  `frais_estimes` decimal(12,2) DEFAULT '0.00',
  `frais_finals` decimal(12,2) DEFAULT '0.00',
  `date_creation_ordre` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `signature_dg` tinyint(1) DEFAULT '0',
  `id_chauffeur` int DEFAULT NULL,
  `id_vehicule` int DEFAULT NULL,
  `observations` text,
  `date_modification` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id_ordre`),
  UNIQUE KEY `id_demande` (`id_demande`),
  KEY `id_chauffeur` (`id_chauffeur`),
  KEY `id_vehicule` (`id_vehicule`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

